import{a2 as e,a3 as o,an as s}from"./index.f8c2d56a.js";const c={class:"md-blog m-auto text-left"},d=s('<h1 id="c-%E8%AF%AD%E8%A8%80%E5%B8%B8%E7%94%A8-i%2Fo-%E5%87%BD%E6%95%B0" tabindex="-1">C \u8BED\u8A00\u5E38\u7528 I/O \u51FD\u6570</h1><p>\u672C\u6587\u6C47\u603B\u4E86 C \u8BED\u8A00\u4E2D\u4E00\u4E9B\u5E38\u89C1\u7684\u8F93\u5165\u8F93\u51FA\u51FD\u6570\uFF0C\u6765\u6E90\u4E8E stdio \u5E93\u3002<s>\u4E0A\u5B66\u671F\u8001\u5E08\u8BB2\u7684\u5B9E\u5728\u592A\u5C11</s></p><h2 id="%E5%9F%BA%E6%9C%AC%E7%9A%84%E8%BE%93%E5%85%A5%E8%BE%93%E5%87%BA%E5%87%BD%E6%95%B0" tabindex="-1">\u57FA\u672C\u7684\u8F93\u5165\u8F93\u51FA\u51FD\u6570</h2><ul><li><code>printf</code> \u4E0E <code>scanf</code></li><li><code>getchar</code> \u4E0E <code>putchar</code></li><li><code>gets</code> \u4E0E <code>puts</code></li></ul><p>\u4ECE\u6807\u51C6\u8F93\u5165\u8F93\u51FA\u6D41\uFF08<strong>stdin</strong> \u548C <strong>stdout</strong>\uFF09\u8BFB\u5165\u8BFB\u51FA\u6570\u636E\u3002\u672A\u88AB\u91CD\u5B9A\u5411\u65F6\u9ED8\u8BA4\u662F <strong>\u952E\u76D8</strong> \u548C <strong>\u7EC8\u7AEF</strong>\u3002</p><p>\u5176\u4E2D <code>gets</code> \u5728\u8BFB\u53D6\u6570\u636E\u65F6\u672A\u5BF9\u7F13\u51B2\u533A\u5927\u5C0F\u4F5C\u51FA\u9650\u5236\uFF0C\u8F83\u4E0D\u5B89\u5168\uFF0C\u4E0D\u63A8\u8350\u4F7F\u7528\u3002</p><p><code>printf</code> \u548C <code>scanf</code> \u4F5C\u7528\u662F\u8F93\u51FA / \u8BFB\u53D6\u683C\u5F0F\u5316\u5B57\u7B26\u4E32\u3002\u683C\u5F0F\u5316\u5B57\u7B26\u4E32\u4E2D\u5B58\u5728\u53EF\u6307\u5B9A\u7684\u53D8\u91CF\uFF0C\u4F8B\u5982 %d \u6307\u793A\u6574\u578B\u53D8\u91CF\uFF0C\u5BF9\u5E94\u7684\u503C\u5199\u5728\u683C\u5F0F\u5316\u5B57\u7B26\u4E32\u4E4B\u540E\u3002</p><p><code>getchar</code> \u548C <code>putchar</code> \u4EC5\u80FD\u8BFB\u5165 / \u8F93\u5165\u5355\u4E2A\u5B57\u7B26\u3002</p><p><code>puts</code> \u4EC5\u80FD\u8F93\u51FA\u6307\u5B9A\u5B57\u7B26\u4E32\u3002</p><h2 id="%E5%85%B6%E4%BB%96%E5%AE%9E%E7%94%A8%E7%9A%84-i%2Fo-%E5%87%BD%E6%95%B0" tabindex="-1">\u5176\u4ED6\u5B9E\u7528\u7684 I/O \u51FD\u6570</h2><h3 id="ungetc" tabindex="-1">ungetc</h3><p>\u58F0\u660E\uFF1A<code>int ungetc(int char, FILE *stream)</code></p><p>\u4F5C\u7528\uFF1A\u5C06\u6307\u5B9A\u7684\u5B57\u7B26\u4E22\u56DE\u6307\u5B9A\u6D41\u4E2D\uFF08\u4F8B\u5982 stdin\uFF09\uFF0C\u53EF\u4EE5\u4FBF\u4E8E\u540E\u9762\u7684\u6574\u4F53\u8BFB\u53D6\u3002</p><h3 id="fgets" tabindex="-1">fgets</h3><p>\u58F0\u660E\uFF1A<code>char *fgets(char *str, int n, FILE *stream)</code></p><p>\u4F5C\u7528\uFF1A\u4E00\u6B21\u4ECE\u6D41\u4E2D\u8BFB\u53D6\u4E00\u884C\uFF0C\u5B58\u5230 str \u4E2D\u3002</p><p>\u6CE8\u610F\uFF1A\u5F53\u4E00\u884C\u6570\u76EE\u6CA1\u6709\u8FBE\u5230 n \u65F6\uFF0C\u9664\u4E86\u672B\u5C3E\u7684\u2019\\0\u2019\u6807\u8BC6\u5B57\u7B26\u4E32\u7ED3\u675F\uFF0C\u5728\u2019\\0\u2019\u4E4B\u524D\u8FD8\u4F1A\u6709\u6362\u884C\u7B26\u2019\\n\u2019\u3002</p><h3 id="snprintf" tabindex="-1">snprintf</h3><p>\u58F0\u660E\uFF1A<code>int snprintf(char *str, size_t size, const char *format, ...)</code></p><p>\u4F5C\u7528\uFF1A\u5411\u5B57\u7B26\u4E32 str \u4E2D\u8F93\u5165\u683C\u5F0F\u5316\u5B57\u7B26\u4E32\uFF0C\u4F8B\u5982\uFF1A</p><p><code>snprintf(str,100,&quot;%s%s&quot;,str1,str2)</code> \u8D77\u5230\u4E86\u628A str1 \u548C str2 \u62FC\u63A5\u540E\u5B58\u5165 str \u7684\u6548\u679C\u3002</p><h3 id="freopen" tabindex="-1">freopen</h3><p>\u58F0\u660E\uFF1A<code>FILE *freopen(const char *filename, const char *mode, FILE *stream)</code></p><p>\u4F5C\u7528\uFF1A\u8F93\u5165\u8F93\u51FA\u6D41\u7684\u91CD\u5B9A\u5411\u3002\u4F8B\u5982\uFF1A <code>freopen(&quot;file.txt&quot;, &quot;w+&quot;, stdout)</code> \u5C06\u6807\u51C6\u8F93\u51FA\u6D41\u91CD\u5B9A\u5411\u5230 file.txt\u3002</p><h2 id="%E7%BB%93%E6%9D%9F%E8%BE%93%E5%85%A5%E6%9D%A1%E4%BB%B6%E5%88%A4%E6%96%AD" tabindex="-1">\u7ED3\u675F\u8F93\u5165\u6761\u4EF6\u5224\u65AD</h2><p>\u89C1 <a href="https://blog.csdn.net/Jaster_wisdom/article/details/81161896">\u6B64\u6587</a>\u3002</p><h2 id="%E6%80%BB%E7%BB%93" tabindex="-1">\u603B\u7ED3</h2><p>\u5176\u5B9E\u8FD9\u65B9\u9762\u5185\u5BB9\u6709\u4EC0\u4E48\u95EE\u9898\u67E5\u67E5\u6587\u6863\u5C31\u884C\uFF0C\u672C\u6587\u662F\u6311\u9009\u4E86\u4E00\u4E9B\u4F7F\u7528\u7684\u5F52\u7EB3\u4E00\u4E0B\u3002\u5728\u8003\u8651\u5904\u7406\u8F93\u5165\u8F93\u51FA\u9700\u8981\u600E\u4E48\u6837\u7684\u51FD\u6570\u65F6\uFF0C\u4E3B\u8981\u8003\u8651\u8F93\u5165\u8F93\u51FA\u662F <strong>\u5B57\u7B26\u4E32</strong> \u8FD8\u662F <strong>\u6807\u51C6\u8F93\u5165\u8F93\u51FA\u6D41</strong> \u8FD8\u662F <strong>\u6587\u4EF6\u6D41</strong>\uFF08\u5904\u7406\u6807\u51C6\u8F93\u5165\u8F93\u51FA\u6D41\u65F6\u4E5F\u53EF\u4EE5\u5229\u7528\u5904\u7406\u6587\u4EF6\u6D41\u7684\u51FD\u6570\uFF09\uFF0C\u7136\u540E\u4F9D\u636E\u9700\u6C42\u9009\u62E9\u51FD\u6570\u5373\u53EF\u3002</p>',28),n=[d],h={setup(r,{expose:t}){return t({frontmatter:{}}),(i,a)=>(e(),o("div",c,n))}};export{h as default};
